												var geti = function () {
													if (cards.contains(card)) {
														return cards.indexOf(card);
													}
													return cards.length;
												};
												if (get.name(card) == 'shan') return Math.min(num, [6, 4, 3][Math.min(geti(), 2)]) * 0.6;
												return Math.max(num, [6.5, 4, 3][Math.min(geti(), 2)]);
