											if (event.card.name == 'sha' && typeof get.number(event.card) == 'number') {
												for (var target of event.targets) {
													var info = get.info(event.card);
													var range = info.range;
													var outrange = info.outrange;
													if (range == undefined && outrange == undefined) return false;

													if (player.hasSkill('undist') || target.hasSkill('undist')) return false;
													for (var i in range) {
														if (i == 'attack') {
															if (player.inRange(target)) return false;
															var range2 = player.getAttackRange();
															if (range2 <= 0) return get.distance(player, target) <= get.number(card);
															var distance = get.distance(player, target) + extra;
															if (range[i] <= distance - range2) return get.distance(player, target) <= get.number(card);
														}
														else {
															var distance = get.distance(player, target, i) + extra;
															if (range[i] < distance) return get.distance(player, target) <= get.number(card);
														}
													}
													for (var i in outrange) {
														if (i == 'attack') {
															var range2 = player.getAttackRange();
															if (range2 <= 0) return get.distance(player, target) <= get.number(card);
															var distance = get.distance(player, target) + extra;
															if (outrange[i] > distance - range2 + 1) return get.distance(player, target) <= get.number(card);
														}
														else {
															var distance = get.distance(player, target, i) + extra;
															if (outrange[i] > distance) return get.distance(player, target) <= get.number(card);
														}
													}
												}
											}
											return false;
