									//////赫默
									"ark_yanxue": {
										trigger: {
											global: ["loseAfter", "equipAfter", "addJudgeAfter", "gainAfter", "loseAsyncAfter"],
										},
										usable: 1,
										filter: function (event, player) {
											if (get.itemtype(event.player) != "player") return false;
											var evt = event.getl(event.player);
											return evt && evt.hs && evt.hs.length && event.player == _status.currentPhase && event.player.num('h') == 0 && event.player.isAlive();
										},
										content: function () {
											'step 0'
											var cards = get.cards(4);
											var dis = [];
											player.showCards(cards);
											var maxnum = player.getMaxCard(".number", cards).number;
											var minnum = player.getMinCard(".number", cards).number;
											event.cards = [];
											for (var i = 0; i < cards.length; i++) {
												if (cards[i].number != maxnum && cards[i].number != minnum) event.cards.push(cards[i]);
												else dis.push(cards[i]);
											}
											if (dis.length > 0) player.discard(dis);
											if (event.cards.length > 0) player.gain(event.cards, 'gain2');
											'step 1'
											if (player.countCards('h') == 0) {
												event.goto(2);
												return;
											};
											var cards = player.getCards('h');
											var sum = 0;
											for (var i = 0; i < cards.length; i++) {
												sum += cards[i].number;
											}
											event.num = sum / player.countCards('h');
											var players = game.filterPlayer();
											if (event.num > players.length) event.finish();
											'step 2'
											if (game.hasPlayer(function (target) {
												return target.isLinked() || target.isTurnedOver();
											})) player.chooseTarget('你可以令一名角色复原武将牌');
											else {
												player.say('原来这就是没有人受伤的世界');
												event.finish();
											}
											'step 3'
											if (result.bool && result.targets) {
												event.target = result.targets[0];
												if (event.target != player) player.line(event.target);
												if (event.target.isTurnedOver()) event.target.turnOver();
												if (event.target.isLinked()) event.target.link();
											}
										},
									},
