									"ark_jidui": "协勠",
									"ark_jidui_info": "「<font color=red>挈阵荡决</font>」<br><li>主公技，其他同势力角色使用实体【杀】结算完后，若之未造成伤害，其可以令你摸一张牌。",
									ark_zhongwu: '重武',
